// // This module decrements the count value on each positive edge of the clock signal clk if the enable signal en is asserted. If the reset signal rst is asserted, the counter is incremented to the maximum value on the next clock cycle.
module counter_with_enable(
    input clk,
    input rst,
    input en,

    output reg [3:0] count
);
    always @(posedge clk) begin
        if (rst)
            count <= 4'b0000;
        else if (en)
            count <= count + 1;
    end
endmodule
